const Navbar = ({ onLoginClick, onSignupClick }) => {
  const token = localStorage.getItem('token');
  
  return (
    <nav className="fixed top-4 left-1/2 -translate-x-1/2 w-[90%] z-[100] px-8 py-4 bg-white/10 backdrop-blur-xl border border-white/20 rounded-2xl flex justify-between items-center">
      <div className="text-2xl font-black bg-gradient-to-r from-purple-400 to-pink-600 bg-clip-text text-transparent">
        TASK.IO
      </div>
      <div className="flex gap-4">
        {!token ? (
          <>
            <button onClick={onLoginClick} className="text-white text-sm font-bold">Login</button>
            <button onClick={onSignupClick} className="bg-white text-black px-4 py-2 rounded-xl text-sm font-bold">Join</button>
          </>
        ) : (
          <button onClick={() => {localStorage.clear(); window.location.reload();}} className="text-red-400 text-sm font-bold">Logout</button>
        )}
      </div>
    </nav>
  );
};
